"""Connectors for local text files."""

import os
from csv import DictReader
from pathlib import Path
from typing import Any, Callable, Dict, Iterator, List, Optional, Union
from zlib import adler32

from bytewax.inputs import FixedPartitionedSource, StatefulSourcePartition, batch
from bytewax.outputs import FixedPartitionedSink, StatefulSinkPartition
from typing_extensions import override


def _get_path_dev(path: Path) -> str:
    return hex(path.stat().st_dev)


def _readlines(f) -> Iterator[str]:
    """Turn a file into a generator of lines but support `tell`.

    Python files don't support `tell` to learn the offset if you use
    them in iterator mode via `next`, so re-create that iterator using
    `readline`.

    """
    while True:
        line = f.readline()
        if len(line) <= 0:
            break
        yield line


def _strip_n(s: str) -> str:
    return s.rstrip("\n")


class _FileSourcePartition(StatefulSourcePartition[str, int]):
    def __init__(self, path: Path, batch_size: int, resume_state: Optional[int]):
        self._f = open(path, "rt")
        if resume_state is not None:
            self._f.seek(resume_state)
        it = map(_strip_n, _readlines(self._f))
        self._batcher = batch(it, batch_size)

    @override
    def next_batch(self) -> List[str]:
        return next(self._batcher)

    @override
    def snapshot(self) -> int:
        return self._f.tell()

    @override
    def close(self) -> None:
        self._f.close()


class DirSource(FixedPartitionedSource[str, int]):
    """Read all files in a filesystem directory line-by-line.

    The directory must exist on at least one worker. Each worker can
    have unique files at overlapping paths if each worker mounts a
    distinct filesystem. Tries to read only one instance of each
    unique file in the whole cluster by deduplicating paths by
    filesystem ID. See `get_fs_id` argument to adjust this.

    Unique files are the unit of parallelism; only one worker will
    read each unique file. Thus, lines from different files are
    interleaved.

    Can support exactly-once processing.

    """

    def __init__(
        self,
        dir_path: Path,
        glob_pat: str = "*",
        batch_size: int = 1000,
        get_fs_id: Callable[[Path], str] = _get_path_dev,
    ):
        """Init.

        :arg dir_path: Path to directory.

        :arg glob_pat: Pattern of files to read from the directory.
            Defaults to `"*"` or all files.

        :arg batch_size: Number of lines to read per batch. Defaults
            to 1000.

        :arg get_fs_id: Called with the directory and must return a
            consistent (across workers and restarts) unique ID for the
            filesystem of that directory. Defaults to using
            {py:obj}`os.stat_result.st_dev`.

            If you know all workers have access to identical files,
            you can have this return a constant: `lambda _dir:
            "SHARED"`.

        """
        if not dir_path.exists():
            msg = f"input directory `{dir_path}` does not exist"
            raise ValueError(msg)
        if not dir_path.is_dir():
            msg = f"input directory `{dir_path}` is not a directory"
            raise ValueError(msg)

        self._dir_path = dir_path
        self._glob_pat = glob_pat
        self._batch_size = batch_size
        self._fs_id = get_fs_id(dir_path)
        if "::" in self._fs_id:
            msg = f"result of `get_fs_id` must not contain `::`; got {self._fs_id!r}"
            raise ValueError(msg)

    @override
    def list_parts(self) -> List[str]:
        if self._dir_path.exists():
            return [
                f"{self._fs_id}::{path.relative_to(self._dir_path)}"
                for path in self._dir_path.glob(self._glob_pat)
            ]
        else:
            return []

    @override
    def build_part(
        self, step_id: str, for_part: str, resume_state: Optional[int]
    ) -> _FileSourcePartition:
        _fs_id, for_path = for_part.split("::", 1)
        path = self._dir_path / for_path
        return _FileSourcePartition(path, self._batch_size, resume_state)


class FileSource(FixedPartitionedSource[str, int]):
    """Read a path line-by-line from the filesystem.

    The path must exist on at least one worker. Each worker can have a
    unique file at the path if each worker mounts a distinct
    filesystem. Tries to read only one instance of each unique file in
    the whole cluster by deduplicating paths by filesystem ID. See
    `get_fs_id` argument to adjust this.

    Unique files are the unit of parallelism; only one worker will
    read each unique file. Thus, lines from different files are
    interleaved.

    """

    def __init__(
        self,
        path: Union[Path, str],
        batch_size: int = 1000,
        get_fs_id: Callable[[Path], str] = _get_path_dev,
    ):
        """Init.

        :arg path: Path to file.

        :arg batch_size: Number of lines to read per batch. Defaults
            to 1000.

        :arg get_fs_id: Called with the parent directory and must
            return a consistent (across workers and restarts) unique
            ID for the filesystem of that directory. Defaults to using
            {py:obj}`os.stat_result.st_dev`.

            If you know all workers have access to identical files,
            you can have this return a constant: `lambda _dir:
            "SHARED"`.

        """
        if not isinstance(path, Path):
            path = Path(path)

        self._path = path
        self._batch_size = batch_size
        self._fs_id = get_fs_id(path.parent)
        if "::" in self._fs_id:
            msg = f"result of `get_fs_id` must not contain `::`; got {self._fs_id!r}"
            raise ValueError(msg)

    @override
    def list_parts(self) -> List[str]:
        if self._path.exists():
            return [f"{self._fs_id}::{self._path}"]
        else:
            return []

    @override
    def build_part(
        self, step_id: str, for_part: str, resume_state: Optional[int]
    ) -> _FileSourcePartition:
        _fs_id, path = for_part.split("::", 1)
        # TODO: Warn and return None. Then we could support
        # continuation from a different file.
        assert path == str(self._path), "Can't resume reading from different file"
        return _FileSourcePartition(self._path, self._batch_size, resume_state)


class _CSVPartition(StatefulSourcePartition[Dict[str, str], int]):
    def __init__(
        self,
        path: Path,
        batch_size: int,
        resume_state: Optional[int],
        fmtparams: Dict[str, Any],
    ):
        self._f = open(path, "rt", newline="")
        reader = DictReader(_readlines(self._f), **fmtparams)
        # Force reading of the header.
        _ = reader.fieldnames
        if resume_state is not None:
            self._f.seek(resume_state)
        self._batcher = batch(reader, batch_size)

    @override
    def next_batch(self) -> List[Dict[str, str]]:
        return next(self._batcher)

    @override
    def snapshot(self) -> int:
        return self._f.tell()

    @override
    def close(self) -> None:
        self._f.close()


class CSVSource(FixedPartitionedSource[Dict[str, str], int]):
    """Read a path as a CSV file row-by-row as keyed-by-column dicts.

    The path must exist on at least one worker. Each worker can have a
    unique file at the path if each worker mounts a distinct
    filesystem. Tries to read only one instance of each unique file in
    the whole cluster by deduplicating paths by filesystem ID. See
    `get_fs_id` argument to adjust this.

    Unique files are the unit of parallelism; only one worker will
    read each unique file. Thus, lines from different files are
    interleaved.

    Sample input:

    ```
    index,timestamp,value,instance
    0,2022-02-24 11:42:08,0.132,24ae8d
    0,2022-02-24 11:42:08,0.066,c6585a
    0,2022-02-24 11:42:08,42.652,ac20cd
    ```

    Sample output:

    ```json
    {
        "index": "0",
        "timestamp": "2022-02-24 11:42:08",
        "value": "0.132",
        "instance": "24ae8d",
    }
    {
        "index": "0",
        "timestamp": "2022-02-24 11:42:08",
        "value": "0.066",
        "instance": "c6585a",
    }
    {
        "index": "0",
        "timestamp": "2022-02-24 11:42:08",
        "value": "42.652",
        "instance": "ac20cd",
    }
    ```
    """

    def __init__(
        self,
        path: Path,
        batch_size: int = 1000,
        get_fs_id: Callable[[Path], str] = _get_path_dev,
        **fmtparams,
    ):
        """Init.

        :arg path: Path to file.

        :arg batch_size: Number of lines to read per batch. Defaults
            to 1000.

        :arg get_fs_id: Called with the parent directory and must
            return a consistent (across workers and restarts) unique
            ID for the filesystem of that directory. Defaults to using
            {py:obj}`os.stat_result.st_dev`.

            If you know all workers have access to identical files,
            you can have this return a constant: `lambda _dir:
            "SHARED"`.

        :arg **fmtparams: Any custom formatting arguments you can pass
            to {py:obj}`csv.reader`.

        """
        self._file_source = FileSource(path, batch_size, get_fs_id)
        self._fmtparams = fmtparams

    @override
    def list_parts(self) -> List[str]:
        return self._file_source.list_parts()

    @override
    def build_part(self, step_id: str, for_part: str, resume_state: Optional[Any]):
        _fs_id, path = for_part.split("::", 1)
        assert path == str(
            self._file_source._path
        ), "Can't resume reading from different file"
        return _CSVPartition(
            self._file_source._path,
            self._file_source._batch_size,
            resume_state,
            self._fmtparams,
        )


class _FileSinkPartition(StatefulSinkPartition[str, int]):
    def __init__(self, path: Path, resume_state: Optional[int], end: str):
        resume_offset = 0 if resume_state is None else resume_state
        self._f = open(path, "at")
        self._f.seek(resume_offset)
        self._f.truncate()
        self._end = end

    @override
    def write_batch(self, values: List[str]) -> None:
        for value in values:
            self._f.write(value)
            self._f.write(self._end)
        self._f.flush()
        os.fsync(self._f.fileno())

    @override
    def snapshot(self) -> int:
        return self._f.tell()

    @override
    def close(self) -> None:
        self._f.close()


class DirSink(FixedPartitionedSink[str, int]):
    """Write to a set of files in a filesystem directory line-by-line.

    Items consumed from the dataflow must look like two-tuples of
    `(key, value)`, where the value must look like a string. Use a
    proceeding map step to do custom formatting.

    The directory must exist and contain identical data on all
    workers, so either run on a single machine or use a shared mount.

    Individual files are the unit of parallelism.

    Can support exactly-once processing in a batch context. Each file
    will be truncated during resume so duplicates are
    prevented. Tailing the output files will result in undefined
    behavior.
    """

    def __init__(
        self,
        dir_path: Path,
        file_count: int,
        file_namer: Callable[[int, int], str] = lambda i, _n: f"part_{i}",
        assign_file: Callable[[str], int] = lambda k: adler32(k.encode()),
        end: str = "\n",
    ):
        """Init.

        :arg dir_path: Path to directory.

        :arg file_count: Number of separate partition files to create.

        :arg file_namer: Will be called with two arguments, the file
            index and total file count, and must return the file name
            to use for that file partition. Defaults to naming files
            like `"part_{i}"`, where `i` is the file index.

        :arg assign_file: Will be called with the key of each consumed
            item and must return the file index the value will be
            written to. Will wrap to the file count if you return a
            larger value. Defaults to calling {py:obj}`zlib.adler32`
            as a simple globally-consistent hash.

        :arg end: String to write after each item. Defaults to
            newline.

        """
        self._dir_path = dir_path
        self._file_count = file_count
        self._file_namer = file_namer
        self._assign_file = assign_file
        self._end = end

    @override
    def list_parts(self) -> List[str]:
        return [self._file_namer(i, self._file_count) for i in range(self._file_count)]

    @override
    def part_fn(self, item_key: str) -> int:
        return self._assign_file(item_key)

    @override
    def build_part(
        self, step_id: str, for_part: str, resume_state: Optional[int]
    ) -> _FileSinkPartition:
        path = self._dir_path / for_part
        return _FileSinkPartition(path, resume_state, self._end)


class FileSink(FixedPartitionedSink[str, int]):
    """Write to a single file line-by-line on the filesystem.

    Items consumed from the dataflow must look like a string. Use a
    proceeding map step to do custom formatting.

    The file must exist and be identical on all workers.

    There is no parallelism; only one worker will actually write to
    the file.

    Can support exactly-once processing in a batch context. The file
    will be truncated during resume so duplicates are
    prevented. Tailing the output file will result in undefined
    behavior.
    """

    def __init__(self, path: Path, end: str = "\n"):
        """Init.

        :arg path: Path to file.

        :arg end: String to write after each item. Defaults to
            newline.

        """
        self._path = path
        self._end = end

    @override
    def list_parts(self) -> List[str]:
        return [str(self._path)]

    @override
    def part_fn(self, item_key: str) -> int:
        return 0

    @override
    def build_part(
        self, step_id: str, for_part: str, resume_state: Optional[int]
    ) -> _FileSinkPartition:
        # TODO: Warn and return None. Then we could support
        # continuation from a different file.
        assert for_part == str(self._path), "Can't resume writing to different file"
        return _FileSinkPartition(self._path, resume_state, self._end)

        """
        ...

    @abstractmethod
    def notify_at(self) -> Optional[datetime]:
        """Next system time timestamp for which a window might close.

        This will be called periodically to know when to wake up this
        operator to close windows, even if no items were received.

        :returns: System time of when to next wake up.

        """
        ...

    @abstractmethod
    def is_empty(self) -> bool:
        """If no state needs to be maintained anymore.

        This, in general, is if there are no windows currently open.
        But you might have other state that needs to persist across
        resumes, and so might return `True` here to maintain that.

        If `False` is returned here, the entire windower will be
        discarded as to not "leak" memory. A new windower will be
        built if this state key is encountered again.

        :returns: If no state needs to be maintained.

        """
        ...

    @abstractmethod
    def snapshot(self) -> S:
        """Return a immutable copy of the state for recovery.

        This will be called periodically by the runtime.

        The value returned here will be passed back to
        {py:obj}`Windower.build` when resuming.

        The state must be {py:obj}`pickle`-able.

        :::{danger}

        **The state must be effectively immutable!** If any of the
        other functions in this class might be able to mutate the
        state, you must {py:obj}`copy.deepcopy` or something
        equivalent before returning it here.

        :::

        :returns: The immutable state to be {py:obj}`pickle`d.

        """
        ...


@dataclass
class _SlidingWindowerState:
    opened: Dict[int, WindowMetadata] = field(default_factory=dict)


@dataclass
class _SlidingWindowerLogic(WindowerLogic[_SlidingWindowerState]):
    length: timedelta
    offset: timedelta
    align_to: datetime

    state: _SlidingWindowerState

    def intersects(self, timestamp: datetime) -> List[int]:
        since_origin = timestamp - self.align_to
        return list(
            range(
                (since_origin - self.length) // self.offset + 1,
                since_origin // self.offset + 1,
            )
        )

    def _metadata_for(self, window_id: int) -> WindowMetadata:
        open_time = self.align_to + self.offset * window_id
        close_time = open_time + self.length
        return WindowMetadata(open_time, close_time)

    @override
    def open_for(self, timestamp: datetime) -> List[int]:
        in_windows = []
        for window_id in self.intersects(timestamp):
            meta = self.state.opened.get(window_id) or self._metadata_for(window_id)
            self.state.opened.setdefault(window_id, meta)
            in_windows.append(window_id)

        return in_windows

    @override
    def late_for(self, timestamp: datetime) -> List[int]:
        return [window_id for window_id in self.intersects(timestamp)]

    @override
    def merged(self) -> Iterable[Tuple[int, int]]:
        """Sliding windows never merge."""
        return _EMPTY

    @override
    def close_for(self, watermark: datetime) -> Iterable[Tuple[int, WindowMetadata]]:
        closed = [
            (window_id, meta)
            for window_id, meta in self.state.opened.items()
            if meta.close_time <= watermark
        ]
        for window_id, _meta in closed:
            del self.state.opened[window_id]

        return closed

    @override
    def notify_at(self) -> Optional[datetime]:
        return min(
            (meta.close_time for meta in self.state.opened.values()), default=None
        )

    @override
    def is_empty(self) -> bool:
        return len(self.state.opened) <= 0

    @override
    def snapshot(self) -> _SlidingWindowerState:
        return copy.deepcopy(self.state)


LATE_SESSION_ID: int = -1
"""Sentinel window ID assigned to late items."""


@dataclass
class _SessionWindowerState:
    max_key: int = LATE_SESSION_ID
    sessions: Dict[int, WindowMetadata] = field(default_factory=dict)
    merge_queue: List[Tuple[int, int]] = field(default_factory=list)
    """Original ID to new ID."""


def _open_sort(id_meta: Tuple[int, WindowMetadata]) -> datetime:
    _window_id, meta = id_meta
    return meta.open_time


def _session_find_merges(
    sessions: Dict[int, WindowMetadata],
    gap: timedelta,
) -> List[Tuple[int, int]]:
    """Mutates sessions in place."""
    merge_queue = []

    sorted_id_sessions = sorted(sessions.items(), key=_open_sort)
    last_window_id, last_meta = sorted_id_sessions.pop(0)
    for this_id, this_meta in sorted_id_sessions:
        # See if this next window is within the gap from the
        # last close. Since we sorted by open time, this is
        # always the correct direction.
        if this_meta.open_time - last_meta.close_time <= gap:
            # If so, it's a merge. Extend the close time (if
            # it actually expands it; the merged window might
            # be fully within the last window).
            last_meta.close_time = max(last_meta.close_time, this_meta.close_time)
            merge_queue.append((this_id, last_window_id))
            last_meta.merged_ids.add(this_id)
            del sessions[this_id]
        else:
            # If they don't merge, this current window is now
            # the new last window to attempt to merge with in
            # the next iteration.
            last_window_id, last_meta = (this_id, this_meta)

    return merge_queue


@dataclass
class _SessionWindowerLogic(WindowerLogic[_SessionWindowerState]):
    gap: timedelta
    state: _SessionWindowerState

    def _find_merges(self) -> None:
        if len(self.state.sessions) >= 2:
            new_merges = _session_find_merges(
                self.state.sessions,
                self.gap,
            )
            self.state.merge_queue.extend(new_merges)

    @override
    def open_for(self, timestamp: datetime) -> Iterable[int]:
        for window_id, meta in self.state.sessions.items():
            assert meta.open_time <= meta.close_time
            until_open = meta.open_time - timestamp
            since_close = timestamp - meta.close_time
            if until_open <= ZERO_TD and since_close <= ZERO_TD:
                # If we're perfectly within an existing session,
                # re-use that session. No merges possible because no
                # session boundaries changed.
                return (window_id,)
            elif until_open > ZERO_TD and until_open <= self.gap:
                # If we're within the gap before an existing session,
                # re-use the session ID, but also see if any merges
                # occurred.
                meta.open_time = timestamp
                self._find_merges()
                return (window_id,)
            elif since_close > ZERO_TD and since_close <= self.gap:
                # Same if after an existing session.
                meta.close_time = timestamp
                self._find_merges()
                return (window_id,)

        # If we're outside all existing sessions, make anew. No need
        # to merge because we aren't within the gap of any existing
        # session.
        self.state.max_key += 1
        window_id = self.state.max_key
        self.state.sessions[window_id] = WindowMetadata(timestamp, timestamp)
        # Items are never late for a session window.
        return (window_id,)

    @override
    def late_for(self, timestamp: datetime) -> Iterable[int]:
        return (LATE_SESSION_ID,)

    @override
    def merged(self) -> Iterable[Tuple[int, int]]:
        merged = self.state.merge_queue
        self.state.merge_queue = []
        return merged

    @override
    def close_for(self, watermark: datetime) -> Iterable[Tuple[int, WindowMetadata]]:
        try:
            close_after = watermark - self.gap
        except OverflowError:
            close_after = UTC_MIN
        closed = [
            (window_id, meta)
            for window_id, meta in self.state.sessions.items()
            if meta.close_time < close_after
        ]
        for window_id, _meta in closed:
            del self.state.sessions[window_id]

        return closed

    @override
    def notify_at(self) -> Optional[datetime]:
        min_close = min(
            (meta.close_time for meta in self.state.sessions.values()),
            default=None,
        )
        return min_close + self.gap if min_close is not None else None

    @override
    def is_empty(self) -> bool:
        """Never discard state.

        If we re-used a window ID, it's possible a downstream join
        would include incorrect window metadata.

        """
        return False

    @override
    def snapshot(self) -> _SessionWindowerState:
        return copy.deepcopy(self.state)


class Windower(ABC, Generic[S]):
    """A type of window.

    If you're just getting started with windowing operators, see the
    concrete subclasses of {py:obj}`Windower` for built-in options.

    Every subclass of this class must also have a matching
    implementation of {py:obj}`WindowerLogic` that actually implements
    the window.

    """

    @abstractmethod
    def build(self, resume_state: Optional[S]) -> WindowerLogic[S]:
        """Construct a new windower logic instance.

        This should close over any non-state configuration and combine
        it with the resume state to return a prepared
        {py:obj}`WindowerLogic` instance.

        :arg resume_state: Snapshot from the previous call to
            {py:obj}`WindowerLogic.snapshot`, if any.

        :returns: A prepared windower logic.

        """
        ...


@dataclass
class SlidingWindower(Windower[_SlidingWindowerState]):
    """Sliding windows of fixed duration.

    If `offset == length`, windows cover all time but do not overlap.
    Each item will fall in exactly one window. This is equivalent to
    using {py:obj}`TumblingWindower`.

    If `offset < length`, windows overlap. Items could call in
    multiple windows.

    You are not allowed to set `offset > length`, otherwise there
    would be undefined gaps between windows which would lose items.

    Window open times are inclusive, but close times are exclusive.

    :::{warning}

    Changing any of the windowing parameters across executions will
    result in incorrect output for any windows that were open at the
    time of the resume snapshot.

    :::

    :arg length: Length of windows.

    :arg offset: Duration between start times of adjacent windows.

    :arg align_to: Align windows so this instant starts a window. You
        can use this to align all windows to an hour boundary, e.g.

    """

    length: timedelta
    offset: timedelta
    align_to: datetime

    def __post_init__(self):
        if self.offset > self.length:
            msg = (
                "sliding window `offset` can't be longer than `length`; "
                "there would be undefined gaps between windows"
            )
            raise ValueError(msg)

    @override
    def build(
        self, resume_state: Optional[_SlidingWindowerState]
    ) -> _SlidingWindowerLogic:
        state = resume_state if resume_state is not None else _SlidingWindowerState()
        return _SlidingWindowerLogic(self.length, self.offset, self.align_to, state)


@dataclass
class TumblingWindower(Windower[_SlidingWindowerState]):
    """Tumbling windows of fixed duration.

    Each item will fall in exactly one window.

    Window open times are inclusive, but close times are exclusive.

    :::{warning}

    Changing any of the windowing parameters across executions will
    result in incorrect output for any windows that were open at the
    time of the resume snapshot.

    :::

    :arg length: Length of windows.

    :arg align_to: Align windows so this instant starts a window. You
        can use this to align all windows to an hour boundary, e.g.

    """

    length: timedelta
    align_to: datetime

    @override
    def build(
        self, resume_state: Optional[_SlidingWindowerState]
    ) -> _SlidingWindowerLogic:
        state = resume_state if resume_state is not None else _SlidingWindowerState()
        return _SlidingWindowerLogic(self.length, self.length, self.align_to, state)


@dataclass
class SessionWindower(Windower[_SessionWindowerState]):
    """Session windows with a fixed inactivity gap.

